    public Object parseCurrency(Object rawCurrency)
    {
        Object currencyId = this.safeString(rawCurrency, "coin");
        Object code = this.safeCurrencyCode(currencyId);
        Object name = this.safeString(rawCurrency, "name");
        Object networkList = this.safeList(rawCurrency, "networkList");
        Object networks = new java.util.HashMap<String, Object>() {{}};
        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(networkList)); j++)
        {
            Object rawNetwork = Helpers.GetValue(networkList, j);
            Object network = this.safeString(rawNetwork, "network");
            Object networkCode = this.networkIdToCode(network, code);
            Object limits = new java.util.HashMap<String, Object>() {{
                put( "withdraw", new java.util.HashMap<String, Object>() {{
                    put( "min", BingxCore.this.safeNumber(rawNetwork, "withdrawMin") );
                    put( "max", BingxCore.this.safeNumber(rawNetwork, "withdrawMax") );
                }} );
                put( "deposit", new java.util.HashMap<String, Object>() {{
                    put( "min", BingxCore.this.safeNumber(rawNetwork, "depositMin") );
                    put( "max", null );
                }} );
            }};
            Object precision = this.parseNumber(this.parsePrecision(this.safeString(rawNetwork, "withdrawPrecision")));
            Helpers.addElementToObject(networks, networkCode, new java.util.HashMap<String, Object>() {{
    put( "info", rawNetwork );
    put( "id", network );
    put( "network", networkCode );
    put( "fee", BingxCore.this.safeNumber(rawNetwork, "withdrawFee") );
    put( "active", null );
    put( "deposit", BingxCore.this.safeBool(rawNetwork, "depositEnable") );
    put( "withdraw", BingxCore.this.safeBool(rawNetwork, "withdrawEnable") );
    put( "precision", precision );
    put( "limits", limits );
}});
        }
        return this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
            put( "info", rawCurrency );
            put( "code", code );
            put( "id", currencyId );
            put( "precision", null );
            put( "name", name );
            put( "active", null );
            put( "deposit", null );
            put( "withdraw", null );
            put( "networks", networks );
            put( "fee", null );
            put( "limits", null );
            put( "type", "crypto" );
        }});
    }

