    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // mark price
        // {
        //     "symbol": "string",
        //     "lastFundingRate": "string",
        //     "markPrice": "string",
        //     "indexPrice": "string",
        //     "nextFundingTime": "int64"
        // }
        //
        // spot
        //    {
        //        "symbol": "BTC-USDT",
        //        "openPrice": "26032.08",
        //        "highPrice": "26178.86",
        //        "lowPrice": "25968.18",
        //        "lastPrice": "26113.60",
        //        "volume": "1161.79",
        //        "quoteVolume": "30288466.44",
        //        "openTime": "1693081020762",
        //        "closeTime": "1693167420762",
        //  added 2023-11-10:
        //        "bidPrice": 16726.0,
        //        "bidQty": 0.05,
        //        "askPrice": 16726.0,
        //        "askQty": 0.05,
        //    }
        // swap
        //
        //    {
        //        "symbol": "BTC-USDT",
        //        "priceChange": "52.5",
        //        "priceChangePercent": "0.31%", // they started to add the percent sign in value
        //        "lastPrice": "16880.5",
        //        "lastQty": "2.2238",          // only present in swap!
        //        "highPrice": "16897.5",
        //        "lowPrice": "16726.0",
        //        "volume": "245870.1692",
        //        "quoteVolume": "4151395117.73",
        //        "openPrice": "16832.0",
        //        "openTime": 1672026667803,
        //        "closeTime": 1672026648425,
        //  added 2023-11-10:
        //        "bidPrice": 16726.0,
        //        "bidQty": 0.05,
        //        "askPrice": 16726.0,
        //        "askQty": 0.05,
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(ticker, "symbol");
        Object lastQty = this.safeString(ticker, "lastQty");
        // in spot markets, lastQty is not present
        // it's (bad, but) the only way we can check the tickers origin
        Object type = ((Helpers.isTrue((Helpers.isEqual(lastQty, null))))) ? "spot" : "swap";
        market = this.safeMarket(marketId, market, null, type);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object open = this.safeString(ticker, "openPrice");
        Object high = this.safeString(ticker, "highPrice");
        Object low = this.safeString(ticker, "lowPrice");
        Object close = this.safeString(ticker, "lastPrice");
        Object quoteVolume = this.safeString(ticker, "quoteVolume");
        Object baseVolume = this.safeString(ticker, "volume");
        Object percentage = this.safeString(ticker, "priceChangePercent");
        if (Helpers.isTrue(!Helpers.isEqual(percentage, null)))
        {
            percentage = Helpers.replace((String)percentage, (String)"%", (String)"");
        }
        Object change = this.safeString(ticker, "priceChange");
        Object ts = this.safeInteger(ticker, "closeTime");
        if (Helpers.isTrue(Helpers.isEqual(ts, 0)))
        {
            ts = null;
        }
        Object datetime = this.iso8601(ts);
        Object bid = this.safeString(ticker, "bidPrice");
        Object bidVolume = this.safeString(ticker, "bidQty");
        Object ask = this.safeString(ticker, "askPrice");
        Object askVolume = this.safeString(ticker, "askQty");
        final Object finalTs = ts;
        final Object finalPercentage = percentage;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", finalTs );
            put( "datetime", datetime );
            put( "high", high );
            put( "low", low );
            put( "bid", bid );
            put( "bidVolume", bidVolume );
            put( "ask", ask );
            put( "askVolume", askVolume );
            put( "vwap", null );
            put( "open", open );
            put( "close", close );
            put( "last", null );
            put( "previousClose", null );
            put( "change", change );
            put( "percentage", finalPercentage );
            put( "average", null );
            put( "baseVolume", baseVolume );
            put( "quoteVolume", quoteVolume );
            put( "markPrice", BingxCore.this.safeString(ticker, "markPrice") );
            put( "indexPrice", BingxCore.this.safeString(ticker, "indexPrice") );
            put( "info", ticker );
        }}, market);
    }

    /**
     * @method
     * @name bingx#fetchBalance
     * @description query for balance and get the amount of funds available for trading or funds locked in orders
     * @see https://bingx-api.github.io/docs-v3/#/en/Spot/Account%20Endpoints/Query%20Assets
     * @see https://bingx-api.github.io/docs-v3/#/en/Swap/Account%20Endpoints/Query%20account%20data
     * @see https://bingx-api.github.io/docs-v3/#/en/Coin-M%20Futures/Trades%20Endpoints/Query%20Account%20Assets
     * @see https://bingx-api.github.io/docs-v3/#/en/Account%20and%20Wallet/Fund%20Account/Query%20Assets
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.standard] whether to fetch standard contract balances
     * @param {string} [params.type] the type of balance to fetch (spot, swap, funding) default is `spot`
     * @returns {object} a [balance structure]{@link https://docs.ccxt.com/?id=balance-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchBalance(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object response = null;
            Object standard = null;
            var standardparametersVariable = this.handleOptionAndParams(parameters, "fetchBalance", "standard", false);
            standard = ((java.util.List<Object>) standardparametersVariable).get(0);
            parameters = ((java.util.List<Object>) standardparametersVariable).get(1);
            Object subType = null;
            var subTypeparametersVariable = this.handleSubTypeAndParams("fetchBalance", null, parameters);
            subType = ((java.util.List<Object>) subTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) subTypeparametersVariable).get(1);
            var marketTypemarketTypeQueryVariable = this.handleMarketTypeAndParams("fetchBalance", null, parameters);
            var marketType = ((java.util.List<Object>) marketTypemarketTypeQueryVariable).get(0);
            var marketTypeQuery = ((java.util.List<Object>) marketTypemarketTypeQueryVariable).get(1);
            if (Helpers.isTrue(standard))
            {
                response = (this.contractV1PrivateGetBalance(marketTypeQuery)).join();
            } else if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(marketType, "funding"))) || Helpers.isTrue((Helpers.isEqual(marketType, "fund")))))
            {
                response = (this.fundV1PrivateGetAccountBalance(marketTypeQuery)).join();
            } else if (Helpers.isTrue(Helpers.isEqual(marketType, "spot")))
            {
                response = (this.spotV1PrivateGetAccountBalance(marketTypeQuery)).join();
            } else
            {
                if (Helpers.isTrue(Helpers.isEqual(subType, "inverse")))
                {
                    response = (this.cswapV1PrivateGetUserBalance(marketTypeQuery)).join();
                } else
                {
                    response = (this.swapV3PrivateGetUserBalance(marketTypeQuery)).join();
                }
            }
            return this.parseBalance(response);
        });

    }

    public Object parseBalance(Object response)
    {
        //
        // standard
        //
        //     {
        //         "code": 0,
        //         "timestamp": 1721192833454,
        //         "data": [
        //             {
        //                 "asset": "USDT",
        //                 "balance": "4.72644300000000000000",
        //                 "crossWalletBalance": "4.72644300000000000000",
        //                 "crossUnPnl": "0",
        //                 "availableBalance": "4.72644300000000000000",
        //                 "maxWithdrawAmount": "4.72644300000000000000",
        //                 "marginAvailable": false,
        //                 "updateTime": 1721192833443
        //             },
        //         ]
        //     }
        //
        // spot
        //
        //     {
        //         "code": 0,
        //         "msg": "",
        //         "debugMsg": "",
        //         "data": {
        //             "balances": [
        //                 {
        //                     "asset": "USDT",
        //                     "free": "45.733046995800514",
        //                     "locked": "0"
        //                 },
        //             ]
        //         }
        //     }
        //
        // inverse swap
        //
        //     {
        //         "code": 0,
        //         "msg": "",
        //         "timestamp": 1721191833813,
        //         "data": [
        //             {
        //                 "asset": "SOL",
        //                 "balance": "0.35707951",
        //                 "equity": "0.35791051",
        //                 "unrealizedProfit": "0.00083099",
        //                 "availableMargin": "0.35160653",
        //                 "usedMargin": "0.00630397",
        //                 "freezedMargin": "0",
        //                 "shortUid": "12851936"
        //             }
        //         ]
        //     }
        //
        // linear swap
        //
        //     {
        //         "code": 0,
        //         "msg": "",
        //         "data": [
        //             {
        //                 "userId": "116***295",
        //                 "asset": "USDT",
        //                 "balance": "194.8212",
        //                 "equity": "196.7431",
        //                 "unrealizedProfit": "1.9219",
        //                 "realisedProfit": "-109.2504",
        //                 "availableMargin": "193.7609",
        //                 "usedMargin": "1.0602",
        //                 "freezedMargin": "0.0000",
        //                 "shortUid": "12851936"
        //             }
        //         ]
        //     }
        //
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
        }};
        Object contractBalances = this.safeList(response, "data");
        Object firstContractBalances = this.safeDict(contractBalances, 0);
        Object isContract = !Helpers.isEqual(firstContractBalances, null);
        Object spotData = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
        Object spotBalances = this.safeList2(spotData, "balances", "assets", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        if (Helpers.isTrue(isContract))
        {
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(contractBalances)); i++)
            {
                Object balance = Helpers.GetValue(contractBalances, i);
                Object currencyId = this.safeString(balance, "asset");
                if (Helpers.isTrue(Helpers.isEqual(currencyId, null)))
                {
                    break;
                }
                Object code = this.safeCurrencyCode(currencyId);
                Object account = this.account();
                Helpers.addElementToObject(account, "free", this.safeString2(balance, "availableMargin", "availableBalance"));
                Helpers.addElementToObject(account, "used", this.safeString(balance, "usedMargin"));
                Helpers.addElementToObject(account, "total", this.safeString(balance, "maxWithdrawAmount"));
                Helpers.addElementToObject(result, code, account);
            }
        } else
        {
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(spotBalances)); i++)
            {
                Object balance = Helpers.GetValue(spotBalances, i);
                Object currencyId = this.safeString(balance, "asset");
                Object code = this.safeCurrencyCode(currencyId);
                Object account = this.account();
                Helpers.addElementToObject(account, "free", this.safeString(balance, "free"));
                Helpers.addElementToObject(account, "used", this.safeString(balance, "locked"));
                Helpers.addElementToObject(result, code, account);
            }
        }
        return this.safeBalance(result);
    }

    /**
     * @method
     * @name bingx#fetchPositionHistory
     * @description fetches historical positions
     * @see https://bingx-api.github.io/docs-v3/#/en/Swap/Trades%20Endpoints/Query%20Position%20History
     * @param {string} symbol unified contract symbol
     * @param {int} [since] the earliest time in ms to fetch positions for
     * @param {int} [limit] the maximum amount of records to fetch
     * @param {object} [params] extra parameters specific to the exchange api endpoint
     * @param {int} [params.until] the latest time in ms to fetch positions for
     * @returns {object[]} a list of [position structures]{@link https://docs.ccxt.com/?id=position-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchPositionHistory(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object since = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "pageSize", limit);
            }
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "startTs", since);
            }
            var requestparametersVariable = this.handleUntilOption("endTs", request, parameters);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            Object response = null;
            if (Helpers.isTrue(Helpers.GetValue(market, "linear")))
            {
                response = (this.swapV1PrivateGetTradePositionHistory(this.extend(request, parameters))).join();
            } else
            {
                throw new NotSupported((String)Helpers.add(this.id, " fetchPositionHistory() is not supported for inverse swap positions")) ;
            }
            //
            //     {
            //         "code": 0,
            //         "msg": "",
            //         "data": {
            //             "positionHistory": [
            //                 {
            //                     "positionId": "1861675561156571136",
            //                     "symbol": "LTC-USDT",
            //                     "isolated": false,
            //                     "positionSide": "LONG",
            //                     "openTime": 1732693017000,
            //                     "updateTime": 1733310292000,
            //                     "avgPrice": "95.18",
            //                     "avgClosePrice": "129.48",
            //                     "realisedProfit": "102.89",
            //                     "netProfit": "99.63",
            //                     "positionAmt": "30.0",
            //                     "closePositionAmt": "30.0",
            //                     "leverage": 6,
            //                     "closeAllPositions": true,
            //                     "positionCommission": "-0.33699650000000003",
            //                     "totalFunding": "-2.921461693902908"
            //                 },
            //             ]
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object records = this.safeList(data, "positionHistory", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object positions = this.parsePositions(records);
            return this.filterBySymbolSinceLimit(positions, symbol, since, limit);
        });

    }

