    /**
     * @method
     * @name bingx#fetchPosition
     * @description fetch data on a single open contract trade position
     * @see https://bingx-api.github.io/docs-v3/#/en/Swap/Account%20Endpoints/Query%20position%20data
     * @see https://bingx-api.github.io/docs-v3/#/en/Coin-M%20Futures/Trades%20Endpoints/Query%20warehouse
     * @param {string} symbol unified market symbol of the market the position is held in
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [position structure]{@link https://docs.ccxt.com/?id=position-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchPosition(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            if (!Helpers.isTrue(Helpers.GetValue(market, "swap")))
            {
                throw new BadRequest((String)Helpers.add(this.id, " fetchPosition() supports swap markets only")) ;
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object response = null;
            if (Helpers.isTrue(Helpers.GetValue(market, "inverse")))
            {
                response = (this.cswapV1PrivateGetUserPositions(this.extend(request, parameters))).join();
            } else
            {
                response = (this.swapV2PrivateGetUserPositions(this.extend(request, parameters))).join();
            }
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object first = this.safeDict(data, 0, new java.util.HashMap<String, Object>() {{}});
            return this.parsePosition(first, market);
        });

    }

    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        // inverse swap
        //
        //     {
        //         "symbol": "SOL-USD",
        //         "positionId": "1813080351385337856",
        //         "positionSide": "LONG",
        //         "isolated": false,
        //         "positionAmt": "1",
        //         "availableAmt": "1",
        //         "unrealizedProfit": "-0.00009074",
        //         "initialMargin": "0.00630398",
        //         "liquidationPrice": 23.968303426677032,
        //         "avgPrice": "158.63",
        //         "leverage": 10,
        //         "markPrice": "158.402",
        //         "riskRate": "0.00123783",
        //         "maxMarginReduction": "0",
        //         "updateTime": 1721107015848
        //     }
        //
        // linear swap
        //
        //     {
        //         "positionId": "1792480725958881280",
        //         "symbol": "LTC-USDT",
        //         "currency": "USDT",
        //         "positionAmt": "0.1",
        //         "availableAmt": "0.1",
        //         "positionSide": "LONG",
        //         "isolated": false,
        //         "avgPrice": "83.53",
        //         "initialMargin": "1.3922",
        //         "margin": "0.3528",
        //         "leverage": 6,
        //         "unrealizedProfit": "-1.0393",
        //         "realisedProfit": "-0.2119",
        //         "liquidationPrice": 0,
        //         "pnlRatio": "-0.7465",
        //         "maxMarginReduction": "0.0000",
        //         "riskRate": "0.0008",
        //         "markPrice": "73.14",
        //         "positionValue": "7.3136",
        //         "onlyOnePosition": true,
        //         "updateTime": 1721088016688
        //     }
        //
        // standard position
        //
        //     {
        //         "currentPrice": "82.91",
        //         "symbol": "LTC/USDT",
        //         "initialMargin": "5.00000000000000000000",
        //         "unrealizedProfit": "-0.26464500",
        //         "leverage": "20.000000000",
        //         "isolated": true,
        //         "entryPrice": "83.13",
        //         "positionSide": "LONG",
        //         "positionAmt": "1.20365912",
        //     }
        //
        // linear swap fetchPositionHistory
        //
        //     {
        //         "positionId": "1861675561156571136",
        //         "symbol": "LTC-USDT",
        //         "isolated": false,
        //         "positionSide": "LONG",
        //         "openTime": 1732693017000,
        //         "updateTime": 1733310292000,
        //         "avgPrice": "95.18",
        //         "avgClosePrice": "129.48",
        //         "realisedProfit": "102.89",
        //         "netProfit": "99.63",
        //         "positionAmt": "30.0",
        //         "closePositionAmt": "30.0",
        //         "leverage": 6,
        //         "closeAllPositions": true,
        //         "positionCommission": "-0.33699650000000003",
        //         "totalFunding": "-2.921461693902908"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = ((String)this.safeString(position, "symbol", ""));
        marketId = Helpers.replace((String)marketId, (String)"/", (String)"-"); // standard return different format
        Object isolated = this.safeBool(position, "isolated");
        Object marginMode = null;
        if (Helpers.isTrue(!Helpers.isEqual(isolated, null)))
        {
            marginMode = ((Helpers.isTrue(isolated))) ? "isolated" : "cross";
        }
        Object timestamp = this.safeInteger(position, "openTime");
        final Object finalMarketId = marketId;
        final Object finalMarginMode = marginMode;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", BingxCore.this.safeString(position, "positionId") );
            put( "symbol", BingxCore.this.safeSymbol(finalMarketId, market, "-", "swap") );
            put( "notional", BingxCore.this.safeNumber(position, "positionValue") );
            put( "marginMode", finalMarginMode );
            put( "liquidationPrice", null );
            put( "entryPrice", BingxCore.this.safeNumber2(position, "avgPrice", "entryPrice") );
            put( "unrealizedPnl", BingxCore.this.safeNumber(position, "unrealizedProfit") );
            put( "realizedPnl", BingxCore.this.safeNumber(position, "realisedProfit") );
            put( "percentage", null );
            put( "contracts", BingxCore.this.safeNumber(position, "positionAmt") );
            put( "contractSize", null );
            put( "markPrice", BingxCore.this.safeNumber(position, "markPrice") );
            put( "lastPrice", null );
            put( "side", BingxCore.this.safeStringLower(position, "positionSide") );
            put( "hedged", null );
            put( "timestamp", timestamp );
            put( "datetime", BingxCore.this.iso8601(timestamp) );
            put( "lastUpdateTimestamp", BingxCore.this.safeInteger(position, "updateTime") );
            put( "maintenanceMargin", null );
            put( "maintenanceMarginPercentage", null );
            put( "collateral", null );
            put( "initialMargin", BingxCore.this.safeNumber(position, "initialMargin") );
            put( "initialMarginPercentage", null );
            put( "leverage", BingxCore.this.safeNumber(position, "leverage") );
            put( "marginRatio", null );
            put( "stopLossPrice", null );
            put( "takeProfitPrice", null );
        }});
    }

