    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // fetchDeposits
        //
        //    {
        //        "amount":"0.00999800",
        //        "coin":"PAXG",
        //        "network":"ETH",
        //        "status":1,
        //        "address":"0x788cabe9236ce061e5a892e1a59395a81fc8d62c",
        //        "addressTag":"",
        //        "txId":"0xaad4654a3234aa6118af9b4b335f5ae81c360b2394721c019b5d1e75328b09f3",
        //        "insertTime":1599621997000,
        //        "transferType":0,
        //        "unlockConfirm":"12/12", // confirm times for unlocking
        //        "confirmTimes":"12/12"
        //    }
        //
        // fetchWithdrawals
        //
        //    {
        //        "address": "0x94df8b352de7f46f64b01d3666bf6e936e44ce60",
        //        "amount": "8.91000000",
        //        "applyTime": "2019-10-12 11:12:02",
        //        "coin": "USDT",
        //        "id": "b6ae22b3aa844210a7041aee7589627c",
        //        "withdrawOrderId": "WITHDRAWtest123",
        //        "network": "ETH",
        //        "transferType": 0
        //        "status": 6,
        //        "transactionFee": "0.004",
        //        "confirmNo":3,
        //        "info": "The address is not valid. Please confirm with the recipient",
        //        "txId": "0xb5ef8c13b968a406cc62a93a8bd80f9e9a906ef1b3fcf20a2e48573c17659268"
        //    }
        //
        // withdraw
        //
        //     {
        //         "code":0,
        //         "timestamp":1705274263621,
        //         "data":{
        //             "id":"1264246141278773252"
        //         }
        //     }
        //
        // parse withdraw-type output first...
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object data = this.safeValue(transaction, "data");
        Object dataId = ((Helpers.isTrue((Helpers.isEqual(data, null))))) ? null : this.safeString(data, "id");
        Object id = this.safeString(transaction, "id", dataId);
        Object address = this.safeString(transaction, "address");
        Object tag = this.safeString(transaction, "addressTag");
        Object timestamp = this.safeInteger2(transaction, "insertTime", "timestamp");
        Object datetime = this.iso8601(timestamp);
        if (Helpers.isTrue(Helpers.isEqual(timestamp, null)))
        {
            datetime = this.safeString(transaction, "applyTime");
            timestamp = this.parse8601(datetime);
        }
        Object network = this.safeString(transaction, "network");
        Object currencyId = this.safeString(transaction, "coin");
        Object code = this.safeCurrencyCode(currencyId, currency);
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(code, null))) && Helpers.isTrue((!Helpers.isEqual(code, network)))) && Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(code, network), 0))))
        {
            if (Helpers.isTrue(!Helpers.isEqual(network, null)))
            {
                code = Helpers.replace((String)code, (String)network, (String)"");
            }
        }
        Object rawType = this.safeString(transaction, "transferType");
        Object type = ((Helpers.isTrue((Helpers.isEqual(rawType, "0"))))) ? "deposit" : "withdrawal";
        final Object finalCode = code;
        final Object finalNetwork = network;
        final Object finalTimestamp = timestamp;
        final Object finalDatetime = datetime;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", id );
            put( "txid", BingxCore.this.safeString(transaction, "txId") );
            put( "type", type );
            put( "currency", finalCode );
            put( "network", BingxCore.this.networkIdToCode(finalNetwork, finalCode) );
            put( "amount", BingxCore.this.safeNumber(transaction, "amount") );
            put( "status", BingxCore.this.parseTransactionStatus(BingxCore.this.safeString(transaction, "status")) );
            put( "timestamp", finalTimestamp );
            put( "datetime", finalDatetime );
            put( "address", address );
            put( "addressFrom", null );
            put( "addressTo", address );
            put( "tag", tag );
            put( "tagFrom", tag );
            put( "tagTo", null );
            put( "updated", null );
            put( "comment", BingxCore.this.safeString(transaction, "info") );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "currency", finalCode );
                put( "cost", BingxCore.this.safeNumber(transaction, "transactionFee") );
                put( "rate", null );
            }} );
            put( "internal", null );
        }};
    }

    public Object parseTransactionStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "0", "pending" );
            put( "1", "ok" );
            put( "10", "pending" );
            put( "20", "rejected" );
            put( "30", "ok" );
            put( "40", "rejected" );
            put( "50", "ok" );
            put( "60", "pending" );
            put( "70", "rejected" );
            put( "2", "pending" );
            put( "3", "rejected" );
            put( "4", "pending" );
            put( "5", "rejected" );
            put( "6", "ok" );
        }};
        return this.safeString(statuses, status, status);
    }

    /**
     * @method
     * @name bingx#setMarginMode
     * @description set margin mode to 'cross' or 'isolated'
     * @see https://bingx-api.github.io/docs-v3/#/en/Swap/Trades%20Endpoints/Change%20Margin%20Type
     * @see https://bingx-api.github.io/docs-v3/#/en/Coin-M%20Futures/Trades%20Endpoints/Set%20Margin%20Type
     * @param {string} marginMode 'cross' or 'isolated'
     * @param {string} symbol unified market symbol
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} response from the exchange
     */
    public java.util.concurrent.CompletableFuture<Object> setMarginMode(Object marginMode2, Object... optionalArgs)
    {
        final Object marginMode3 = marginMode2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object marginMode = marginMode3;
            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " setMarginMode() requires a symbol argument")) ;
            }
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            if (Helpers.isTrue(!Helpers.isEqual(Helpers.GetValue(market, "type"), "swap")))
            {
                throw new BadSymbol((String)Helpers.add(this.id, " setMarginMode() supports swap contracts only")) ;
            }
            marginMode = ((String)marginMode).toUpperCase();
            if (Helpers.isTrue(Helpers.isEqual(marginMode, "CROSS")))
            {
                marginMode = "CROSSED";
            }
            if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(marginMode, "ISOLATED")) && Helpers.isTrue(!Helpers.isEqual(marginMode, "CROSSED"))))
            {
                throw new BadRequest((String)Helpers.add(this.id, " setMarginMode() marginMode argument should be isolated or cross")) ;
            }
            final Object finalMarginMode = marginMode;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "marginType", finalMarginMode );
            }};
            Object subType = null;
            var subTypeparametersVariable = this.handleSubTypeAndParams("setMarginMode", market, parameters);
            subType = ((java.util.List<Object>) subTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) subTypeparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(subType, "inverse")))
            {
                return (this.cswapV1PrivatePostTradeMarginType(this.extend(request, parameters))).join();
            } else
            {
                return (this.swapV2PrivatePostTradeMarginType(this.extend(request, parameters))).join();
            }
        });

    }

