    public Object parseLiquidation(Object liquidation, Object... optionalArgs)
    {
        //
        //     {
        //         "time": "int64",
        //         "symbol": "string",
        //         "side": "string",
        //         "type": "string",
        //         "positionSide": "string",
        //         "cumQuote": "string",
        //         "status": "string",
        //         "stopPrice": "string",
        //         "price": "string",
        //         "origQty": "string",
        //         "avgPrice": "string",
        //         "executedQty": "string",
        //         "orderId": "int64",
        //         "profit": "string",
        //         "commission": "string",
        //         "workingType": "string",
        //         "updateTime": "int64"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(liquidation, "symbol");
        Object timestamp = this.safeInteger(liquidation, "time");
        Object contractsString = this.safeString(liquidation, "executedQty");
        Object contractSizeString = this.safeString(market, "contractSize");
        Object priceString = this.safeString(liquidation, "avgPrice");
        Object baseValueString = Precise.stringMul(contractsString, contractSizeString);
        Object quoteValueString = Precise.stringMul(baseValueString, priceString);
        return this.safeLiquidation(new java.util.HashMap<String, Object>() {{
            put( "info", liquidation );
            put( "symbol", BingxCore.this.safeSymbol(marketId, market) );
            put( "contracts", BingxCore.this.parseNumber(contractsString) );
            put( "contractSize", BingxCore.this.parseNumber(contractSizeString) );
            put( "price", BingxCore.this.parseNumber(priceString) );
            put( "baseValue", BingxCore.this.parseNumber(baseValueString) );
            put( "quoteValue", BingxCore.this.parseNumber(quoteValueString) );
            put( "timestamp", timestamp );
            put( "datetime", BingxCore.this.iso8601(timestamp) );
        }});
    }

